import numpy as np

def predict(frame, action):
    next_frame = frame.copy()
    if action == 6:
        # Rule for action 6: Change the color of a specific cell (e.g., top-left corner to 10)
        next_frame[0, 0] = 10
    elif action == 7:
        # Rule for action 7: No change in the grid
        pass
    return next_frame
